INSERT INTO vocab_grammar_qa (id, academy_id, student_id, student_name, question, answer, status, answered_by, include_in_print, grade, exam_problem, created_at, answered_at) VALUES ('vqa-sb-5b1209fb-c10', 'acad-1', NULL, NULL, '현재완료의 have + p.p. 구조를 설명해줘', '답변 생성 실패', 'answered', 'ai', 1, NULL, NULL, '2026-03-20T05:41:21.168827+00:00', '2026-03-20T05:41:21.168827+00:00') ON CONFLICT(id) DO NOTHING;
INSERT INTO vocab_grammar_qa (id, academy_id, student_id, student_name, question, answer, status, answered_by, include_in_print, grade, exam_problem, created_at, answered_at) VALUES ('vqa-sb-7d0bb489-e20', 'acad-1', NULL, NULL, 'be동사와 일반동사의 차이는?', 'be동사(am/is/are/was/were)는 주어의 상태나 존재를 나타내며 보어와 함께 쓰인다. 일반동사는 동작이나 상태를 나타내며 do/does/did로 의문문과 부정문을 만든다. 예: She is happy.(be동사) / She likes music.(일반동사)', 'answered', 'teacher', 1, 1, NULL, '2026-03-20T06:03:32.529941+00:00', '2026-03-20T06:03:32.529941+00:00') ON CONFLICT(id) DO NOTHING;
INSERT INTO vocab_grammar_qa (id, academy_id, student_id, student_name, question, answer, status, answered_by, include_in_print, grade, exam_problem, created_at, answered_at) VALUES ('vqa-sb-08b56098-437', 'acad-1', NULL, NULL, '현재시제와 현재진행형의 차이는?', '현재시제(V/Vs)는 반복적인 습관, 일반적 사실, 불변의 진리를 나타낸다. 현재진행형(be+Ving)은 지금 이 순간 진행 중인 동작을 나타낸다. 예: He reads books every day.(습관) / He is reading now.(진행 중)', 'answered', 'teacher', 1, 1, NULL, '2026-03-20T06:03:33.315996+00:00', '2026-03-20T06:03:33.315996+00:00') ON CONFLICT(id) DO NOTHING;
INSERT INTO vocab_grammar_qa (id, academy_id, student_id, student_name, question, answer, status, answered_by, include_in_print, grade, exam_problem, created_at, answered_at) VALUES ('vqa-sb-b70a1328-c36', 'acad-1', NULL, NULL, '과거시제와 현재완료의 차이는?', '과거시제(V-ed)는 특정 과거 시점의 사건을 나타내고, 현재완료(have+p.p.)는 과거의 경험·결과·완료가 현재와 연결될 때 사용한다. 예: I visited Paris last year.(과거) / I have visited Paris before.(경험)', 'answered', 'teacher', 1, 1, NULL, '2026-03-20T06:03:33.952896+00:00', '2026-03-20T06:03:33.952896+00:00') ON CONFLICT(id) DO NOTHING;
INSERT INTO vocab_grammar_qa (id, academy_id, student_id, student_name, question, answer, status, answered_by, include_in_print, grade, exam_problem, created_at, answered_at) VALUES ('vqa-sb-5693e3b0-975', 'acad-1', NULL, NULL, '조동사 can, may, must의 의미 차이는?', 'can은 능력(~할 수 있다) 또는 허가(~해도 된다)를, may는 허가(~해도 된다) 또는 추측(~일지도 모른다)을, must는 의무(~해야 한다) 또는 강한 추측(~임에 틀림없다)을 나타낸다. 예: You must be tired.(강한 추측)', 'answered', 'teacher', 1, 1, NULL, '2026-03-20T06:03:34.572483+00:00', '2026-03-20T06:03:34.572483+00:00') ON CONFLICT(id) DO NOTHING;
INSERT INTO vocab_grammar_qa (id, academy_id, student_id, student_name, question, answer, status, answered_by, include_in_print, grade, exam_problem, created_at, answered_at) VALUES ('vqa-sb-3603d3c4-019', 'acad-1', NULL, NULL, 'to부정사의 명사적, 형용사적, 부사적 용법의 차이는?', '명사적 용법: 주어·목적어·보어 역할(To read is good.), 형용사적 용법: 앞의 명사를 수식(I have books to read.), 부사적 용법: 목적·결과·원인 등 표현(She studied hard to pass.).', 'answered', 'teacher', 1, 1, NULL, '2026-03-20T06:03:35.187672+00:00', '2026-03-20T06:03:35.187672+00:00') ON CONFLICT(id) DO NOTHING;
INSERT INTO vocab_grammar_qa (id, academy_id, student_id, student_name, question, answer, status, answered_by, include_in_print, grade, exam_problem, created_at, answered_at) VALUES ('vqa-sb-96bae196-bf7', 'acad-1', NULL, NULL, '동명사와 to부정사를 목적어로 취하는 동사의 차이는?', '동명사만 목적어: enjoy, finish, avoid, mind, keep 등. to부정사만 목적어: want, hope, plan, decide, refuse 등. 둘 다 가능하지만 의미 다름: remember/forget/try/stop + 동명사(과거) vs to부정사(미래/의도).', 'answered', 'teacher', 1, 1, NULL, '2026-03-20T06:05:46.734028+00:00', '2026-03-20T06:05:46.734028+00:00') ON CONFLICT(id) DO NOTHING;
INSERT INTO vocab_grammar_qa (id, academy_id, student_id, student_name, question, answer, status, answered_by, include_in_print, grade, exam_problem, created_at, answered_at) VALUES ('vqa-sb-a0fd3daf-2ac', 'acad-1', NULL, NULL, '관계대명사 who, which, that의 사용법은?', 'who는 사람 선행사, which는 사물/동물 선행사, that은 사람/사물 모두 가능하다. 주격·목적격·소유격(whose)으로 구분된다. 선행사가 -thing, -body, 최상급, 서수일 때는 that을 선호한다. 예: the boy who(that) won / the book which(that) I read', 'answered', 'teacher', 1, 1, NULL, '2026-03-20T06:05:47.549893+00:00', '2026-03-20T06:05:47.549893+00:00') ON CONFLICT(id) DO NOTHING;
INSERT INTO vocab_grammar_qa (id, academy_id, student_id, student_name, question, answer, status, answered_by, include_in_print, grade, exam_problem, created_at, answered_at) VALUES ('vqa-sb-dfdbb8c8-49a', 'acad-1', NULL, NULL, '관계부사 when, where, why, how의 사용법은?', '관계부사는 선행사+전치사+관계대명사로 바꿀 수 있다. when(선행사: 시간), where(장소), why(reason), how(방법, 선행사 생략). 예: the place where he lives = the place in which he lives.', 'answered', 'teacher', 1, 1, NULL, '2026-03-20T06:05:48.242668+00:00', '2026-03-20T06:05:48.242668+00:00') ON CONFLICT(id) DO NOTHING;
INSERT INTO vocab_grammar_qa (id, academy_id, student_id, student_name, question, answer, status, answered_by, include_in_print, grade, exam_problem, created_at, answered_at) VALUES ('vqa-sb-63fb7001-7d9', 'acad-1', NULL, NULL, '접속사 and, but, or, so, because의 차이는?', 'and(그리고/병렬), but(그러나/대조), or(또는/선택), so(그래서/결과), because(왜냐하면/이유). 등위접속사는 문법적으로 대등한 요소를 연결한다. 예: He was tired, so he went to bed early.', 'answered', 'teacher', 1, 1, NULL, '2026-03-20T06:05:48.954277+00:00', '2026-03-20T06:05:48.954277+00:00') ON CONFLICT(id) DO NOTHING;
INSERT INTO vocab_grammar_qa (id, academy_id, student_id, student_name, question, answer, status, answered_by, include_in_print, grade, exam_problem, created_at, answered_at) VALUES ('vqa-sb-90e72604-958', 'acad-1', NULL, NULL, '비교급과 최상급의 형태와 용법은?', '1·2음절 형용사: -er/-est(taller/tallest), 3음절 이상: more/most+원급. 비교급+than(~보다), the+최상급+in/of(~중에서 가장). 예: She is taller than I am. / He is the tallest in his class.', 'answered', 'teacher', 1, 1, NULL, '2026-03-20T06:05:49.660101+00:00', '2026-03-20T06:05:49.660101+00:00') ON CONFLICT(id) DO NOTHING;
INSERT INTO vocab_grammar_qa (id, academy_id, student_id, student_name, question, answer, status, answered_by, include_in_print, grade, exam_problem, created_at, answered_at) VALUES ('vqa-sb-3502aa8c-ff0', 'acad-1', NULL, NULL, '수동태의 기본 구조는?', '수동태: 주어+be동사+과거분사(by+행위자). 능동태의 목적어가 수동태의 주어가 된다. 시제는 be동사로 표현. 예: She wrote the letter.(능동) → The letter was written by her.(수동)', 'answered', 'teacher', 1, 1, NULL, '2026-03-20T06:11:31.332948+00:00', '2026-03-20T06:11:31.332948+00:00') ON CONFLICT(id) DO NOTHING;
INSERT INTO vocab_grammar_qa (id, academy_id, student_id, student_name, question, answer, status, answered_by, include_in_print, grade, exam_problem, created_at, answered_at) VALUES ('vqa-sb-5a34937b-761', 'acad-1', NULL, NULL, 'there is/are 구문의 사용법은?', 'there is+단수명사, there are+복수명사로 ~이 있다를 표현한다. there는 형식상 주어이며 진주어는 뒤에 온다. 예: There is a book on the desk. / There are many students in the room.', 'answered', 'teacher', 1, 1, NULL, '2026-03-20T06:11:32.007085+00:00', '2026-03-20T06:11:32.007085+00:00') ON CONFLICT(id) DO NOTHING;
INSERT INTO vocab_grammar_qa (id, academy_id, student_id, student_name, question, answer, status, answered_by, include_in_print, grade, exam_problem, created_at, answered_at) VALUES ('vqa-sb-7a0ba5ad-e9d', 'acad-1', NULL, NULL, 'it ~ that 강조구문과 가주어 it의 차이는?', '가주어 it: It is important to study hard.(진주어: to study hard) - it 자리에 진주어를 되돌릴 수 없음. 강조구문: It is Tom that broke the window.(강조되는 요소를 it is~that 사이에 넣음) - that 이하 완전한 문장 X.', 'answered', 'teacher', 1, 1, NULL, '2026-03-20T06:11:32.622046+00:00', '2026-03-20T06:11:32.622046+00:00') ON CONFLICT(id) DO NOTHING;
INSERT INTO vocab_grammar_qa (id, academy_id, student_id, student_name, question, answer, status, answered_by, include_in_print, grade, exam_problem, created_at, answered_at) VALUES ('vqa-sb-4bbd8ba7-452', 'acad-1', NULL, NULL, '시간/조건 부사절에서 현재시제가 미래를 대신하는 규칙은?', 'when, if, after, before, until, as soon as 등 시간·조건 부사절에서는 현재시제가 미래를 대신한다. 주절에는 미래시제를 쓴다. 예: When she arrives, I will call you.(arrives 현재, will call 미래)', 'answered', 'teacher', 1, 1, NULL, '2026-03-20T06:11:33.230462+00:00', '2026-03-20T06:11:33.230462+00:00') ON CONFLICT(id) DO NOTHING;
INSERT INTO vocab_grammar_qa (id, academy_id, student_id, student_name, question, answer, status, answered_by, include_in_print, grade, exam_problem, created_at, answered_at) VALUES ('vqa-sb-787296e4-e68', 'acad-1', NULL, NULL, '형용사와 부사의 차이는?', '형용사는 명사를 수식하거나 보어 역할(be동사 뒤)을 한다. 부사는 동사·형용사·부사·문장 전체를 수식한다. 대부분 형용사에 -ly를 붙여 부사 생성. 예: She is beautiful.(형용사) / She sings beautifully.(부사)', 'answered', 'teacher', 1, 1, NULL, '2026-03-20T06:11:33.837456+00:00', '2026-03-20T06:11:33.837456+00:00') ON CONFLICT(id) DO NOTHING;
INSERT INTO vocab_grammar_qa (id, academy_id, student_id, student_name, question, answer, status, answered_by, include_in_print, grade, exam_problem, created_at, answered_at) VALUES ('vqa-sb-bc730a41-ad2', 'acad-1', NULL, NULL, '가정법 과거와 가정법 과거완료의 차이는?', '가정법 과거: If+주어+동사 과거형, 주어+would/could/might+동사원형 → 현재 사실의 반대 가정. 가정법 과거완료: If+주어+had+p.p., 주어+would/could/might+have+p.p. → 과거 사실의 반대 가정. 예: If I were rich, I could buy it.(현재 부자가 아님) / If I had studied harder, I would have passed.(과거 충분히 공부 안 했음)', 'answered', 'teacher', 1, 2, NULL, '2026-03-20T06:13:32.228701+00:00', '2026-03-20T06:13:32.228701+00:00') ON CONFLICT(id) DO NOTHING;
INSERT INTO vocab_grammar_qa (id, academy_id, student_id, student_name, question, answer, status, answered_by, include_in_print, grade, exam_problem, created_at, answered_at) VALUES ('vqa-sb-fb1dd118-36a', 'acad-1', NULL, NULL, '분사구문의 의미와 만드는 방법은?', '부사절을 분사구문으로 바꾸는 법: 접속사 삭제, 주절과 주어 같으면 삭제, 동사를 현재분사(V-ing)로. 의미: 시간·이유·조건·양보·동시동작 등. 예: As she was tired, she went to bed. → Being tired, she went to bed.', 'answered', 'teacher', 1, 2, NULL, '2026-03-20T06:13:33.009847+00:00', '2026-03-20T06:13:33.009847+00:00') ON CONFLICT(id) DO NOTHING;
INSERT INTO vocab_grammar_qa (id, academy_id, student_id, student_name, question, answer, status, answered_by, include_in_print, grade, exam_problem, created_at, answered_at) VALUES ('vqa-sb-8a714ffe-815', 'acad-1', NULL, NULL, '도치구문(부정어 도치)이란?', '부정어(Never, Hardly, Seldom, Not until, Only 등)가 문두에 올 때 주어와 (조)동사가 도치된다. 예: Never have I seen such a sight. / Hardly had he left when she arrived. 수능에서 강조·문학적 표현으로 자주 출제됨.', 'answered', 'teacher', 1, 2, NULL, '2026-03-20T06:13:33.654663+00:00', '2026-03-20T06:13:33.654663+00:00') ON CONFLICT(id) DO NOTHING;
INSERT INTO vocab_grammar_qa (id, academy_id, student_id, student_name, question, answer, status, answered_by, include_in_print, grade, exam_problem, created_at, answered_at) VALUES ('vqa-sb-d2ed1e87-c99', 'acad-1', NULL, NULL, 'It ~ that 강조구문의 심화 용법은?', 'It is/was+강조 요소(주어/목적어/부사)+that+나머지. 강조 요소가 사람이면 who도 가능. that절은 강조 요소를 빼면 완전한 문장이 됨. 예: It was yesterday that he called me.(yesterday 강조) - that절: he called me(완전)', 'answered', 'teacher', 1, 2, NULL, '2026-03-20T06:13:34.28034+00:00', '2026-03-20T06:13:34.28034+00:00') ON CONFLICT(id) DO NOTHING;
INSERT INTO vocab_grammar_qa (id, academy_id, student_id, student_name, question, answer, status, answered_by, include_in_print, grade, exam_problem, created_at, answered_at) VALUES ('vqa-sb-349b6dbf-6ff', 'acad-1', NULL, NULL, '관계사의 계속적 용법(비제한적 용법)이란?', '쉼표 뒤에 which/who가 오는 비제한적 용법은 선행사에 추가 설명을 더한다. that은 계속적 용법에 사용 불가. which가 앞 절 전체를 받을 수 있음. 예: He passed the exam, which surprised everyone.(which = 앞 절 전체)', 'answered', 'teacher', 1, 2, NULL, '2026-03-20T06:13:34.873524+00:00', '2026-03-20T06:13:34.873524+00:00') ON CONFLICT(id) DO NOTHING;
INSERT INTO vocab_grammar_qa (id, academy_id, student_id, student_name, question, answer, status, answered_by, include_in_print, grade, exam_problem, created_at, answered_at) VALUES ('vqa-sb-6a540fae-b67', 'acad-1', NULL, NULL, '혼합 가정법이란?', '혼합 가정법: 조건절은 가정법 과거완료(If+had+p.p.), 주절은 가정법 과거(would+V). 과거 사실이 현재에 영향 미칠 때 사용. 예: If he had studied harder, he would be in college now.(과거 공부 안 했기 때문에 지금 대학에 없음)', 'answered', 'teacher', 1, 2, NULL, '2026-03-20T06:14:12.749184+00:00', '2026-03-20T06:14:12.749184+00:00') ON CONFLICT(id) DO NOTHING;
INSERT INTO vocab_grammar_qa (id, academy_id, student_id, student_name, question, answer, status, answered_by, include_in_print, grade, exam_problem, created_at, answered_at) VALUES ('vqa-sb-0a38c317-c38', 'acad-1', NULL, NULL, '준동사(to부정사, 동명사, 분사)의 의미상 주어는?', '준동사의 의미상 주어가 문장 주어와 다를 때 표시: to부정사 → for/of+목적격, 동명사 → 소유격(또는 목적격), 분사구문 → 분사 앞에 명사/대명사. 예: It is kind of you to help.(of you - kind 등 사람 성격 형용사) / for him to come', 'answered', 'teacher', 1, 2, NULL, '2026-03-20T06:14:13.365918+00:00', '2026-03-20T06:14:13.365918+00:00') ON CONFLICT(id) DO NOTHING;
INSERT INTO vocab_grammar_qa (id, academy_id, student_id, student_name, question, answer, status, answered_by, include_in_print, grade, exam_problem, created_at, answered_at) VALUES ('vqa-sb-786a645d-429', 'acad-1', NULL, NULL, '사역동사와 지각동사의 목적어 보어 구조는?', '사역동사(make, have, let)+목적어+동사원형/과거분사. 지각동사(see, hear, feel, watch)+목적어+동사원형/현재분사/과거분사. 수동태 시 사역동사는 to부정사로 바뀜. 예: She made him study. → He was made to study.', 'answered', 'teacher', 1, 2, NULL, '2026-03-20T06:14:13.9668+00:00', '2026-03-20T06:14:13.9668+00:00') ON CONFLICT(id) DO NOTHING;
INSERT INTO vocab_grammar_qa (id, academy_id, student_id, student_name, question, answer, status, answered_by, include_in_print, grade, exam_problem, created_at, answered_at) VALUES ('vqa-sb-52482282-8e6', 'acad-1', NULL, NULL, '접속사 although, even though, while, whereas의 의미 차이는?', 'although/even though: 비록 ~이지만(양보). while: ~하는 동안(시간) 또는 반면에(대조). whereas: 반면에(대조, 공식적). 예: Although he is rich, he is unhappy. / While she likes coffee, he prefers tea.', 'answered', 'teacher', 1, 2, NULL, '2026-03-20T06:14:14.578228+00:00', '2026-03-20T06:14:14.578228+00:00') ON CONFLICT(id) DO NOTHING;
INSERT INTO vocab_grammar_qa (id, academy_id, student_id, student_name, question, answer, status, answered_by, include_in_print, grade, exam_problem, created_at, answered_at) VALUES ('vqa-sb-f29d3ba1-c1a', 'acad-1', NULL, NULL, '부사절 vs 명사절 that의 구분은?', 'that이 이끄는 명사절은 주어·목적어·보어 역할(He said that she was right.), that이 이끄는 형용사절은 선행사 수식(the fact that she won). 부사절 접속사 that은 so~that(결과), such~that(정도)에서 사용.', 'answered', 'teacher', 1, 2, NULL, '2026-03-20T06:14:15.183139+00:00', '2026-03-20T06:14:15.183139+00:00') ON CONFLICT(id) DO NOTHING;
INSERT INTO vocab_grammar_qa (id, academy_id, student_id, student_name, question, answer, status, answered_by, include_in_print, grade, exam_problem, created_at, answered_at) VALUES ('vqa-sb-0dc57c99-f18', 'acad-1', NULL, NULL, 'with+명사+분사 독립분사구문이란?', 'with+명사+현재분사/과거분사/형용사/전치사구 = ~이 ...한 채로/상태에서. 예: She sat with her eyes closed.(눈을 감은 채) / He spoke with his hands shaking.(손을 떨면서) 부대상황을 나타내는 구문.', 'answered', 'teacher', 1, 2, NULL, '2026-03-20T06:15:08.778718+00:00', '2026-03-20T06:15:08.778718+00:00') ON CONFLICT(id) DO NOTHING;
INSERT INTO vocab_grammar_qa (id, academy_id, student_id, student_name, question, answer, status, answered_by, include_in_print, grade, exam_problem, created_at, answered_at) VALUES ('vqa-sb-d23f4747-6bf', 'acad-1', NULL, NULL, 'to부정사의 완료형(to have+p.p.)의 의미는?', 'to have+p.p.는 주절 동사보다 이전 시점을 나타낸다. 예: He seems to have been rich.(= It seems that he was rich.) / She is said to have left.(= It is said that she left.) 수능 독해에서 자주 등장하는 시제 표현.', 'answered', 'teacher', 1, 2, NULL, '2026-03-20T06:15:09.521806+00:00', '2026-03-20T06:15:09.521806+00:00') ON CONFLICT(id) DO NOTHING;
INSERT INTO vocab_grammar_qa (id, academy_id, student_id, student_name, question, answer, status, answered_by, include_in_print, grade, exam_problem, created_at, answered_at) VALUES ('vqa-sb-19641c9f-fea', 'acad-1', NULL, NULL, '원급 비교의 관용 표현들은?', 'as ~ as 원급 비교: as+원급+as(~만큼). 관용표현: as soon as possible(가능한 빨리), as many/much as(~만큼 많은), not so much A as B(A라기보다 B), as ~ as ever(어느 때보다 ~한). 예: He is not so much a scholar as a writer.', 'answered', 'teacher', 1, 2, NULL, '2026-03-20T06:15:10.2139+00:00', '2026-03-20T06:15:10.2139+00:00') ON CONFLICT(id) DO NOTHING;
INSERT INTO vocab_grammar_qa (id, academy_id, student_id, student_name, question, answer, status, answered_by, include_in_print, grade, exam_problem, created_at, answered_at) VALUES ('vqa-sb-cc0a371c-1af', 'acad-1', NULL, NULL, '명사절을 이끄는 접속사 whether와 if의 차이는?', 'whether와 if 모두 ~인지 아닌지를 나타내지만, 주어·보어·전치사 뒤에는 whether만 사용. or not을 바로 뒤에 붙일 때도 whether only. 예: Whether he comes or not does not matter.(주어절 → if 불가)', 'answered', 'teacher', 1, 2, NULL, '2026-03-20T06:15:10.901083+00:00', '2026-03-20T06:15:10.901083+00:00') ON CONFLICT(id) DO NOTHING;
INSERT INTO vocab_grammar_qa (id, academy_id, student_id, student_name, question, answer, status, answered_by, include_in_print, grade, exam_problem, created_at, answered_at) VALUES ('vqa-sb-a69e62c2-ced', 'acad-1', NULL, NULL, '가정법에서 if 생략 도치는?', 'if를 생략하면 주어·조동사 도치. were, had, should만 가능. 예: If I were you → Were I you / If she had known → Had she known / If he should come → Should he come. 수능 빈출 도치 패턴.', 'answered', 'teacher', 1, 2, NULL, '2026-03-20T06:15:11.556051+00:00', '2026-03-20T06:15:11.556051+00:00') ON CONFLICT(id) DO NOTHING;
INSERT INTO vocab_grammar_qa (id, academy_id, student_id, student_name, question, answer, status, answered_by, include_in_print, grade, exam_problem, created_at, answered_at) VALUES ('vqa-sb-f6a21228-210', 'acad-1', NULL, NULL, '복합관계사(whoever, whatever, whichever, however, whenever, wherever)의 용법은?', '복합관계사는 명사절 또는 부사절을 이끈다. whoever=anyone who(누구든), whatever=anything that(무엇이든), however=no matter how(아무리~해도). 예: Whatever you decide, I will support you. / However hard he tries, he cannot win.', 'answered', 'teacher', 1, 3, NULL, '2026-03-20T06:17:04.770172+00:00', '2026-03-20T06:17:04.770172+00:00') ON CONFLICT(id) DO NOTHING;
INSERT INTO vocab_grammar_qa (id, academy_id, student_id, student_name, question, answer, status, answered_by, include_in_print, grade, exam_problem, created_at, answered_at) VALUES ('vqa-sb-0bbedfb5-711', 'acad-1', NULL, NULL, '수동태의 심화 형태(완료수동, 진행수동, 조동사+수동)는?', '완료수동: have been+p.p. / 진행수동: be being+p.p. / 조동사 수동: must be+p.p. 예: The report has been completed. / The building is being constructed. / The rule should be followed. 수능에서 수동태 판단이 핵심.', 'answered', 'teacher', 1, 3, NULL, '2026-03-20T06:17:05.433791+00:00', '2026-03-20T06:17:05.433791+00:00') ON CONFLICT(id) DO NOTHING;
INSERT INTO vocab_grammar_qa (id, academy_id, student_id, student_name, question, answer, status, answered_by, include_in_print, grade, exam_problem, created_at, answered_at) VALUES ('vqa-sb-7842df42-0ef', 'acad-1', NULL, NULL, '병치(Parallelism)의 원칙이란?', '등위접속사(and, but, or)와 상관접속사(both~and, either~or, neither~nor, not only~but also)로 연결되는 요소는 같은 문법 형태여야 한다. 예: She likes reading, writing, and to sing(X) → reading, writing, and singing(O). 수능 어법 빈출.', 'answered', 'teacher', 1, 3, NULL, '2026-03-20T06:17:06.133462+00:00', '2026-03-20T06:17:06.133462+00:00') ON CONFLICT(id) DO NOTHING;
INSERT INTO vocab_grammar_qa (id, academy_id, student_id, student_name, question, answer, status, answered_by, include_in_print, grade, exam_problem, created_at, answered_at) VALUES ('vqa-sb-0134adc4-633', 'acad-1', NULL, NULL, '분사의 후치 수식과 관계절의 차이는?', '현재분사구(V-ing)는 능동·진행, 과거분사구(p.p.)는 수동·완료를 나타내며 명사를 후치 수식. 관계절로 바꿀 수 있음. 예: the girl sitting by the window(= who is sitting) / the book written by him(= which was written). 수능 어법 핵심.', 'answered', 'teacher', 1, 3, NULL, '2026-03-20T06:17:06.775029+00:00', '2026-03-20T06:17:06.775029+00:00') ON CONFLICT(id) DO NOTHING;
INSERT INTO vocab_grammar_qa (id, academy_id, student_id, student_name, question, answer, status, answered_by, include_in_print, grade, exam_problem, created_at, answered_at) VALUES ('vqa-sb-f39fee81-33e', 'acad-1', NULL, NULL, '부정사 구문 It takes+시간+to부정사 등 관용 표현은?', 'It takes+목적어+시간+to V(~하는데 ...시간이 걸린다), It is no use V-ing(~해도 소용없다), cannot help V-ing(~하지 않을 수 없다), used to V(과거에 ~했다), be used to V-ing(~하는데 익숙하다). 수능 구문 독해 필수.', 'answered', 'teacher', 1, 3, NULL, '2026-03-20T06:17:07.40986+00:00', '2026-03-20T06:17:07.40986+00:00') ON CONFLICT(id) DO NOTHING;
INSERT INTO vocab_grammar_qa (id, academy_id, student_id, student_name, question, answer, status, answered_by, include_in_print, grade, exam_problem, created_at, answered_at) VALUES ('vqa-sb-4e621dbd-548', 'acad-1', NULL, NULL, '수식어 위치 오류(형용사/부사 수식 위치)란?', '부사는 수식하는 단어 바로 앞이나 뒤에 위치해야 의미가 명확하다. only, even, just, almost 등은 위치에 따라 의미 변화. 예: She only told him(그에게만) vs She told only him(그만). 수능 어법에서 수식어 위치가 자주 출제됨.', 'answered', 'teacher', 1, 3, NULL, '2026-03-20T06:18:06.100825+00:00', '2026-03-20T06:18:06.100825+00:00') ON CONFLICT(id) DO NOTHING;
INSERT INTO vocab_grammar_qa (id, academy_id, student_id, student_name, question, answer, status, answered_by, include_in_print, grade, exam_problem, created_at, answered_at) VALUES ('vqa-sb-745754dd-632', 'acad-1', NULL, NULL, '상관접속사(both A and B 등)의 주어·동사 수일치는?', 'both A and B → 복수동사. either A or B / neither A nor B / not only A but also B → B에 동사 수 일치. 예: Not only he but also they are wrong.(they에 일치 → are) / Neither Tom nor his friends are happy.', 'answered', 'teacher', 1, 3, NULL, '2026-03-20T06:18:06.764407+00:00', '2026-03-20T06:18:06.764407+00:00') ON CONFLICT(id) DO NOTHING;
INSERT INTO vocab_grammar_qa (id, academy_id, student_id, student_name, question, answer, status, answered_by, include_in_print, grade, exam_problem, created_at, answered_at) VALUES ('vqa-sb-9d380764-2bd', 'acad-1', NULL, NULL, '관계대명사 what의 특별한 용법은?', 'what은 선행사를 포함한 관계대명사(= the thing(s) which). 명사절을 이끌며 주어·목적어·보어로 사용. 예: What he said was true.(주어절) / I believe what you say.(목적어절) / This is what I wanted.(보어절). that과 혼동 주의.', 'answered', 'teacher', 1, 3, NULL, '2026-03-20T06:18:07.423984+00:00', '2026-03-20T06:18:07.423984+00:00') ON CONFLICT(id) DO NOTHING;
INSERT INTO vocab_grammar_qa (id, academy_id, student_id, student_name, question, answer, status, answered_by, include_in_print, grade, exam_problem, created_at, answered_at) VALUES ('vqa-sb-aa7d54ee-f93', 'acad-1', NULL, NULL, '추측·가능성을 나타내는 조동사 심화(must/can''t/may/might have p.p.)는?', '과거에 대한 추측: must have p.p.(~했음에 틀림없다), cannot have p.p.(~했을 리 없다), may/might have p.p.(~했을지도 모른다), should have p.p.(~했어야 했는데). 예: He must have left already. / You should not have done that.', 'answered', 'teacher', 1, 3, NULL, '2026-03-20T06:18:08.053351+00:00', '2026-03-20T06:18:08.053351+00:00') ON CONFLICT(id) DO NOTHING;
INSERT INTO vocab_grammar_qa (id, academy_id, student_id, student_name, question, answer, status, answered_by, include_in_print, grade, exam_problem, created_at, answered_at) VALUES ('vqa-sb-0ba24ca6-0d1', 'acad-1', NULL, NULL, '절대분사구문과 비인칭독립분사구문이란?', '절대분사구문: 주절과 다른 주어를 분사 앞에 명시. 예: The weather being fine, we went out. / All things considered, ... 비인칭독립분사구문: 관용적으로 주어 생략(의미상 주어=일반인). 예: Strictly speaking, Considering, Talking of, Generally speaking.', 'answered', 'teacher', 1, 3, NULL, '2026-03-20T06:18:08.700872+00:00', '2026-03-20T06:18:08.700872+00:00') ON CONFLICT(id) DO NOTHING;
INSERT INTO vocab_grammar_qa (id, academy_id, student_id, student_name, question, answer, status, answered_by, include_in_print, grade, exam_problem, created_at, answered_at) VALUES ('vqa-sb-fb001466-0fc', 'acad-1', NULL, NULL, '간접의문문의 어순은?', '간접의문문은 의문사+주어+동사 어순(평서문 어순). 예: I do not know where he lives.(O) / I do not know where does he live.(X). 동사 시제: 주절이 과거면 종속절도 과거로 시제 일치. Do you know what time it is?', 'answered', 'teacher', 1, 3, NULL, '2026-03-20T06:18:50.984753+00:00', '2026-03-20T06:18:50.984753+00:00') ON CONFLICT(id) DO NOTHING;
INSERT INTO vocab_grammar_qa (id, academy_id, student_id, student_name, question, answer, status, answered_by, include_in_print, grade, exam_problem, created_at, answered_at) VALUES ('vqa-sb-1b4799ef-c46', 'acad-1', NULL, NULL, '비교급 심화(원급·비교급을 이용한 최상급 표현)는?', 'the+비교급, the+비교급(~할수록 더~), 비교급+and+비교급(점점 더~). 최상급 대신: 원급(No other ~ as 원급 as), 비교급(비교급 than any other). 예: The harder you try, the better you get. / No one runs faster than she does.', 'answered', 'teacher', 1, 3, NULL, '2026-03-20T06:18:51.60653+00:00', '2026-03-20T06:18:51.60653+00:00') ON CONFLICT(id) DO NOTHING;
INSERT INTO vocab_grammar_qa (id, academy_id, student_id, student_name, question, answer, status, answered_by, include_in_print, grade, exam_problem, created_at, answered_at) VALUES ('vqa-sb-d6650708-e15', 'acad-1', NULL, NULL, '명사절 접속사 that vs 관계대명사 that의 구분 기준은?', '명사절 that: that절이 완전한 문장(주어+동사+목적어). 관계대명사 that: that절에 주어 또는 목적어 중 하나 빠진 불완전한 문장. 예: I know that he is honest.(완전 → 명사절) / the fact that he won(완전 → 동격 that) / the boy that I met(불완전 → 관계대명사)', 'answered', 'teacher', 1, 3, NULL, '2026-03-20T06:18:52.21261+00:00', '2026-03-20T06:18:52.21261+00:00') ON CONFLICT(id) DO NOTHING;
INSERT INTO vocab_grammar_qa (id, academy_id, student_id, student_name, question, answer, status, answered_by, include_in_print, grade, exam_problem, created_at, answered_at) VALUES ('vqa-sb-211f8da8-be9', 'acad-1', NULL, NULL, '결과·목적을 나타내는 so/such ~ that 구문은?', 'so+형용사/부사+that: 너무 ~해서 ...하다(결과). such+(a/an)+형용사+명사+that. so that+주어+may/can/will: ~하도록(목적). 예: He was so tired that he fell asleep. / She spoke so clearly that everyone understood. / He left early so that he could catch the bus.', 'answered', 'teacher', 1, 3, NULL, '2026-03-20T06:18:52.819488+00:00', '2026-03-20T06:18:52.819488+00:00') ON CONFLICT(id) DO NOTHING;
INSERT INTO vocab_grammar_qa (id, academy_id, student_id, student_name, question, answer, status, answered_by, include_in_print, grade, exam_problem, created_at, answered_at) VALUES ('vqa-sb-8cd8c635-6ef', 'acad-1', NULL, NULL, '명사를 수식하는 to부정사의 능동·수동 구분은?', '명사+to부정사에서 의미상 수동이면 to be+p.p. 또는 to+V의 형태로 표현. 예: There is nothing to worry about.(worry about의 목적어가 nothing → 능동) / The house to be sold(= which is to be sold 수동). 수능 어법 판단 필수.', 'answered', 'teacher', 1, 3, NULL, '2026-03-20T06:18:53.427492+00:00', '2026-03-20T06:18:53.427492+00:00') ON CONFLICT(id) DO NOTHING;
INSERT INTO vocab_print_jobs (id, academy_id, student_id, word_ids_json, created_by, status, has_writing, started_at, submitted_at, created_at) VALUES ('vpj-sbw-453a2224-de3', 'acad-1', 'gst-sb-ac916ed7-57c', '[]', 'supabase-import', 'voided', 1, '2026-03-19T14:28:21.880864+00:00', NULL, '2026-03-19T14:28:21.880864+00:00') ON CONFLICT(id) DO NOTHING;
INSERT INTO vocab_writing_responses (exam_id, problem_type, problem, target_words, student_answer, grade, graded_at) VALUES ('vpj-sbw-453a2224-de3', 'sentence_completion', '{"type":"sentence_completion","prompt":"","conditions":["과거의 어려움이나 경험을 나타내기 위해 과거완료 시제를 사용할 것.","노력이나 끈기의 중요성을 나타내는 내용을 포함할 것.","미래에 대한 포부나 계획을 나타내는 내용을 포함할 것."],"instruction":"주어진 상황을 바탕으로, 아래 조건에 맞게 영어 문장을 3-5문장으로 영작하시오. 학생이 영어 학습에서 겪는 어려움과 극복 과정, 그리고 앞으로의 목표를 담을 수 있도록 하세요.","expected_length":"3-5문장"}', '[{"id":"750e73a6-7ea1-40f3-9df7-c3b8de8a60b3","korean":"모호한","english":"ambiguous"},{"id":"24d1736d-d247-4d6e-8975-dd8903ed02cb","korean":"유창한","english":"fluent"},{"id":"bcb3ae6a-37fa-4473-824b-e03c75636f5d","korean":"인내하다","english":"persevere"},{"id":"27bddef1-db4a-4357-8c71-4eec1f04d17e","korean":"막연한, 불분명한","english":"vague"}]', NULL, NULL, NULL) ON CONFLICT(exam_id) DO NOTHING;
INSERT INTO vocab_print_jobs (id, academy_id, student_id, word_ids_json, created_by, status, has_writing, started_at, submitted_at, created_at) VALUES ('vpj-sbw-b945e4c8-f1e', 'acad-1', 'gst-sb-ac916ed7-57c', '[]', 'supabase-import', 'voided', 1, '2026-03-19T14:28:45.667243+00:00', NULL, '2026-03-19T14:28:45.667243+00:00') ON CONFLICT(id) DO NOTHING;
INSERT INTO vocab_writing_responses (exam_id, problem_type, problem, target_words, student_answer, grade, graded_at) VALUES ('vpj-sbw-b945e4c8-f1e', 'sentence_completion', '{"type":"sentence_completion","prompt":"어떤 학생이 외국어 학습에 어려움을 겪고 있습니다. 언어 학습 과정에서 애매모호하게 느껴지는 부분들이 많고, 명확한 목표 설정이 어렵습니다. 하지만 포기하지 않고 꾸준히 노력하여 유창하게 말하고 싶어 합니다.","conditions":["과거의 경험을 나타내는 과거완료 시제를 최소 1회 사용하시오.","목표나 의지를 나타내는 to부정사를 최소 2회 사용하시오."],"instruction":"주어진 상황을 바탕으로, 아래 조건에 맞게 3-5문장의 영어 문장을 영작하시오. 핵심 단어를 직접 사용하라는 요구는 없으나, 제시된 단어의 의미를 자연스럽게 포함하도록 내용을 구성하시오.","expected_length":"3-5문장"}', '[{"id":"750e73a6-7ea1-40f3-9df7-c3b8de8a60b3","korean":"모호한","english":"ambiguous"},{"id":"24d1736d-d247-4d6e-8975-dd8903ed02cb","korean":"유창한","english":"fluent"},{"id":"bcb3ae6a-37fa-4473-824b-e03c75636f5d","korean":"인내하다","english":"persevere"},{"id":"27bddef1-db4a-4357-8c71-4eec1f04d17e","korean":"막연한, 불분명한","english":"vague"}]', NULL, NULL, NULL) ON CONFLICT(exam_id) DO NOTHING;
INSERT INTO vocab_print_jobs (id, academy_id, student_id, word_ids_json, created_by, status, has_writing, started_at, submitted_at, created_at) VALUES ('vpj-sbw-22dc4756-6cd', 'acad-1', 'gst-sb-ac916ed7-57c', '[]', 'supabase-import', 'submitted', 1, '2026-03-19T14:29:00.81211+00:00', '2026-03-19T14:29:00.81211+00:00', '2026-03-19T14:29:00.81211+00:00') ON CONFLICT(id) DO NOTHING;
INSERT INTO vocab_writing_responses (exam_id, problem_type, problem, target_words, student_answer, grade, graded_at) VALUES ('vpj-sbw-22dc4756-6cd', 'free_writing', '{"type":"free_writing","prompt":"Imagine you are trying to learn a new skill or hobby. Describe the challenges you face and how you overcome them.","conditions":["Your writing must include at least one sentence that describes an initial uncertainty or lack of clarity about the skill.","Your writing should mention at least one instance where you had to keep trying despite difficulties."],"instruction":"다음 주제에 대해 자신의 생각이나 경험을 4-6문장으로 자유롭게 영어로 작성하시오.","expected_length":"4-6문장"}', '[{"id":"750e73a6-7ea1-40f3-9df7-c3b8de8a60b3","korean":"모호한","english":"ambiguous"},{"id":"24d1736d-d247-4d6e-8975-dd8903ed02cb","korean":"유창한","english":"fluent"},{"id":"bcb3ae6a-37fa-4473-824b-e03c75636f5d","korean":"인내하다","english":"persevere"},{"id":"27bddef1-db4a-4357-8c71-4eec1f04d17e","korean":"막연한, 불분명한","english":"vague"}]', 'I had struggled with English grammar for a long time before I found the right method. Although the process was sometimes ambiguous and vague, I decided to persevere through the difficulties. My goal is to become fluent in English so that I can communicate confidently with people around the world.', '{"total":6,"content":{"score":2,"comment":"학생 답안은 새로운 기술을 배우는 과정에서 겪는 어려움과 극복 방법에 대한 주제를 대체로 잘 다루고 있습니다. ''English grammar''라는 구체적인 기술을 언급하며 초기 어려움(''ambiguous and vague'')과 극복 노력(''persevere'')을 포함하고 있어 조건 1, 2를 충족했습니다. 다만, ''new skill or hobby''라는 폭넓은 주제에 비해 영어 문법 학습이라는 특정 경험에만 국한되어 있어 ''핵심 아이디어의 충분성'' 측면에서 약간의 아쉬움이 있습니다. 새로운 기술/취미를 배우는 과정에 대한 더 일반적이거나 다양한 경험을 추가하면 더 좋을 것입니다.","improvement":"새로운 기술/취미 학습에 대한 경험을 좀 더 구체적으로 묘사하고, 어려움을 극복하는 과정에 대한 추가적인 설명을 덧붙여 보세요. 예를 들어, 어떤 구체적인 어려움이 있었고, 어떻게 해결하려고 노력했는지, 그 결과는 어떠했는지 등을 상세하게 작성하면 내용이 더욱 풍부해질 것입니다."},"structure":{"score":2,"comment":"도입-전개-마무리 구조가 명확하지는 않지만, 문장들이 논리적으로 연결되어 어느 정도의 흐름을 가지고 있습니다. 첫 문장에서 과거의 어려움을, 두 번째 문장에서 극복 의지를, 세 번째 문장에서 목표를 제시하여 간략하게나마 아이디어를 전개하고 있습니다. 다만, 문장 간의 전환이 더 자연스럽고, 각 문장의 역할이 명확하게 구분된다면 구조적인 완성도가 높아질 것입니다.","improvement":"문장 간의 연결을 더 명확하게 하기 위해 접속사나 연결 어구를 활용해 보세요. 예를 들어, 어려움에 대한 설명 후 ''Despite this,'', ''However,'', ''Nevertheless,'' 와 같은 표현을 사용하여 극복 의지를 나타내는 문장으로 전환할 수 있습니다. 또한, 글의 시작 부분에서 어떤 기술을 배우려 했는지, 어려움은 무엇이었는지, 어떻게 극복했는지, 최종 목표는 무엇인지 등 도입, 전개, 마무리를 더 명확히 구성해 보세요."},"expression":{"score":2,"comment":"문법적인 오류는 거의 없으며, ''ambiguous'', ''fluent'', ''persevere'', ''vague''와 같은 참고 어휘를 모두 사용하여 표현력을 높였습니다. 조건 1 (''initial uncertainty or lack of clarity'')과 조건 2 (''keep trying despite difficulties'')를 모두 충족했습니다. 다만, 문장이 다소 짧고 간결하여 더 다양한 어휘나 복잡한 문장 구조를 사용했다면 ''다양한 어휘'' 측면에서 더 높은 점수를 받을 수 있었을 것입니다.","improvement":"참고 어휘를 모두 잘 활용한 점은 훌륭합니다. 더 높은 점수를 받기 위해, 비슷한 의미를 가진 다양한 동의어를 사용하거나, 좀 더 복잡한 문장 구조(예: 관계대명사, 분사구문 등)를 활용하여 글의 표현력을 풍부하게 만들어 보세요. 또한, 문장의 길이를 다양하게 조절하는 것도 글을 더 흥미롭게 만드는 방법입니다."},"word_usage":{"vague":true,"fluent":true,"ambiguous":true,"persevere":true},"model_answer":"When I decided to learn how to play the guitar, I was initially quite uncertain about my ability to even produce a clear sound. The sheer number of strings and chords seemed overwhelming and vague at first. There were many times when my fingers would ache, and I''d hit a discordant note, making me want to give up. However, I remembered my goal of playing my favorite songs for my friends and kept trying. By practicing consistently, even for just a few minutes each day, I gradually improved, and now I can play simple melodies with growing confidence."}', '2026-03-19T14:29:00.81211+00:00') ON CONFLICT(exam_id) DO NOTHING;
INSERT INTO vocab_print_jobs (id, academy_id, student_id, word_ids_json, created_by, status, has_writing, started_at, submitted_at, created_at) VALUES ('vpj-sbw-ee710457-992', 'acad-1', 'gst-sb-bfce39aa-959', '[]', 'supabase-import', 'voided', 1, '2026-03-19T14:45:36.694012+00:00', NULL, '2026-03-19T14:45:36.694012+00:00') ON CONFLICT(id) DO NOTHING;
INSERT INTO vocab_writing_responses (exam_id, problem_type, problem, target_words, student_answer, grade, graded_at) VALUES ('vpj-sbw-ee710457-992', 'sentence_completion', '{"type":"sentence_completion","prompt":"미래는 예측하기 어렵고, 끊임없이 변화하는 세상 속에서 우리는 새로운 도전에 직면하게 됩니다. 이러한 상황 속에서 성공적인 삶을 살아가기 위해서는 끊임없이 배우고 발전하려는 자세가 중요합니다. 또한, 예상치 못한 상황에도 유연하게 대처하고, 목표를 달성하기 위해 최선을 다해야 합니다.","conditions":["과거 시제를 사용하여 학생 시절의 노력을 묘사하는 문장을 하나 포함할 것.","미래의 불확실성에 대해 대처하는 방법을 내용 조건으로 포함할 것."],"instruction":"다음 지문을 읽고, 제시된 조건에 맞게 영어 문장을 3-5문장으로 영작하시오. 학생들의 노력과 미래에 대한 긍정적인 메시지를 담아야 합니다. ''diligent'', ''adjust'', ''utmost'', ''prophecy'', ''inevitable''와 같은 단어의 의미가 자연스럽게 포함될 수 있도록 하되, 단어를 직접 사용해야 하는 것은 아닙니다.","expected_length":"3-5문장"}', '[{"id":"039c27d9-1c4a-40ae-8165-17a3d7191f39","korean":"부지런한","english":"diligent"},{"id":"cbae742f-a5e9-4665-8b99-a7330a157c37","korean":"적응하다","english":"adjust"},{"id":"9e2f25ba-f09a-4d87-bfbb-26356fd73b9f","korean":"최고의, 최대의, 극도의","english":"utmost"},{"id":"0c0ddd9f-14a3-48e7-a317-d7b7898dcd8d","korean":"선행하는","english":"prophecy"},{"id":"083138ee-fde9-4360-a9fc-f2da28949c41","korean":"불가피한","english":"inevitable"}]', NULL, NULL, NULL) ON CONFLICT(exam_id) DO NOTHING;
INSERT INTO vocab_print_jobs (id, academy_id, student_id, word_ids_json, created_by, status, has_writing, started_at, submitted_at, created_at) VALUES ('vpj-sbw-36f7b38e-c0a', 'acad-1', 'gst-sb-bfce39aa-959', '[]', 'supabase-import', 'submitted', 1, '2026-03-19T14:53:55.483009+00:00', '2026-03-19T14:53:55.483009+00:00', '2026-03-19T14:53:55.483009+00:00') ON CONFLICT(id) DO NOTHING;
INSERT INTO vocab_writing_responses (exam_id, problem_type, problem, target_words, student_answer, grade, graded_at) VALUES ('vpj-sbw-36f7b38e-c0a', 'sentence_completion', '{"type":"sentence_completion","prompt":"","conditions":["과거에 대한 후회나 앞으로의 다짐을 나타내는 문장에는 반드시 ''had + p.p.'' 형태를 사용해야 합니다.","미래의 변화나 새로운 환경에 대한 적응을 묘사해야 합니다.","개인의 노력과 어려움 극복에 대한 내용을 포함해야 합니다."],"instruction":"주어진 상황을 바탕으로, 아래 조건에 맞게 영어 문장을 3-5문장으로 완성하시오.","expected_length":"3-5문장"}', '[{"id":"039c27d9-1c4a-40ae-8165-17a3d7191f39","korean":"부지런한","english":"diligent"},{"id":"cbae742f-a5e9-4665-8b99-a7330a157c37","korean":"적응하다","english":"adjust"},{"id":"9e2f25ba-f09a-4d87-bfbb-26356fd73b9f","korean":"최고의, 최대의, 극도의","english":"utmost"},{"id":"0c0ddd9f-14a3-48e7-a317-d7b7898dcd8d","korean":"선행하는","english":"prophecy"},{"id":"083138ee-fde9-4360-a9fc-f2da28949c41","korean":"불가피한","english":"inevitable"}]', 'i dont know', '{"total":0,"content":{"score":0,"comment":"주어진 상황과 문제의 요구사항(과거 후회/미래 다짐, 미래 변화/적응, 개인 노력/어려움 극복)과 전혀 관련이 없습니다. 학생 답안은 무응답에 가깝습니다.","improvement":"문제에서 제시된 세 가지 핵심 요소를 모두 포함하는 내용을 구상해야 합니다. 예를 들어, 과거에 공부를 소홀히 했던 것에 대한 후회, 미래에 더 열심히 공부하겠다는 다짐, 새로운 학업 환경에 적응하려는 노력, 그리고 이를 위해 겪는 어려움과 이를 극복하는 과정을 구체적으로 묘사해야 합니다."},"structure":{"score":0,"comment":"문장 자체가 존재하지 않아 구조를 평가할 수 없습니다.","improvement":"문장을 3-5개로 구성하여 논리적인 흐름을 만들어야 합니다. 도입(상황 제시 또는 후회), 전개(미래 다짐 및 적응 과정), 마무리(노력 강조 또는 결론)와 같이 도입-전개-마무리 구조를 갖추도록 노력해야 합니다."},"expression":{"score":0,"comment":"매우 기본적인 영어 표현조차 제시되지 않아 문법, 어휘, 조건 충족 여부를 평가할 수 없습니다. 모든 조건이 전혀 충족되지 않았습니다.","improvement":"조건 1의 ''had + p.p.'' 구문과 조건 2, 3을 충족하는 문장을 만들어야 합니다. 제시된 참고 어휘(diligent, adjust, utmost, prophecy, inevitable)를 활용하면 표현력을 높일 수 있습니다. 문법적 정확성과 자연스러운 어휘 선택에 유의해야 합니다."},"word_usage":{"adjust":true,"utmost":true,"diligent":true,"prophecy":false,"inevitable":true},"model_answer":"Looking back, I regret that I had not studied harder in my previous school. Now, I am determined to adjust to this new environment and embrace the challenges ahead. I will put in my utmost effort to overcome any difficulties, knowing that hard work is inevitable for growth. I believe that my diligent efforts will lead me to a brighter future."}', '2026-03-19T14:53:55.483009+00:00') ON CONFLICT(exam_id) DO NOTHING;
INSERT INTO vocab_print_jobs (id, academy_id, student_id, word_ids_json, created_by, status, has_writing, started_at, submitted_at, created_at) VALUES ('vpj-sbw-d4b92692-1ad', 'acad-1', 'gst-sb-ac7eba08-fd8', '[]', 'supabase-import', 'voided', 1, '2026-03-19T15:13:44.002316+00:00', NULL, '2026-03-19T15:13:44.002316+00:00') ON CONFLICT(id) DO NOTHING;
INSERT INTO vocab_writing_responses (exam_id, problem_type, problem, target_words, student_answer, grade, graded_at) VALUES ('vpj-sbw-d4b92692-1ad', 'sentence_completion', '{"type":"sentence_completion","prompt":"최근 팀 프로젝트를 진행하면서 팀원들과의 원활한 소통과 협업의 중요성을 다시 한번 느꼈습니다. 하지만 때로는 서로 다른 의견을 조율하고 모두가 만족할 만한 결과물을 도출하는 것이 쉽지 않았습니다. 특히, 각자의 역할 분담과 마감 기한 준수에 있어서 어려움을 겪기도 했습니다.","conditions":["관계대명사(which 또는 that)를 사용하여 팀원들과의 협업 과정에서 느낀 어려움을 하나 이상 언급할 것","프로젝트 성공을 위해 팀원들이 서로의 의견을 존중하고 노력해야 한다는 내용을 포함할 것"],"instruction":"다음 지문을 읽고, 두 가지 조건을 모두 만족하는 영어 문장 3-5개를 영작하시오.","expected_length":"3-5문장"}', '[{"id":"e9ac99cd-8215-4654-83f5-2d7b442a68b6","korean":"인정하다","english":"acknowledge"},{"id":"4b123898-68a7-4d34-ae92-f0ca8077c751","korean":"협력하다","english":"collaborate"},{"id":"c0526a72-05af-46d8-9c21-b45d51a7b522","korean":"충분한","english":"sufficient"},{"id":"f4cfe4a2-9a29-48ae-b56c-224f95adecb4","korean":"정확한","english":"accurate"},{"id":"c29da4c5-6a10-47d4-93ab-c182112e3521","korean":"수용하다","english":"accommodate"}]', NULL, NULL, NULL) ON CONFLICT(exam_id) DO NOTHING;
INSERT INTO vocab_print_jobs (id, academy_id, student_id, word_ids_json, created_by, status, has_writing, started_at, submitted_at, created_at) VALUES ('vpj-sbw-18479f84-06a', 'acad-1', 'gst-sb-bfce39aa-959', '[]', 'supabase-import', 'voided', 1, '2026-03-19T15:50:26.935187+00:00', NULL, '2026-03-19T15:50:26.935187+00:00') ON CONFLICT(id) DO NOTHING;
INSERT INTO vocab_writing_responses (exam_id, problem_type, problem, target_words, student_answer, grade, graded_at) VALUES ('vpj-sbw-18479f84-06a', 'sentence_completion', '{"type":"sentence_completion","prompt":"A young aspiring writer, struggling with self-doubt, reflects on their creative process. They often feel like their stories are already written, waiting to be discovered.  They also wonder if their shy demeanor hinders their ability to share their work effectively with others.","conditions":["과거의 경험을 회상하며 현재 상황을 설명하는 내용을 포함해야 합니다. (e.g., ''used to'', ''would'')","주어진 내용 속 ''미리 결정된, 예정된''이라는 의미를 내포하는 단어를 활용하여 글을 완성하세요."],"instruction":"다음 주어진 상황을 읽고, 조건에 맞게 3-5문장으로 영어 영작하세요.","expected_length":"3-5문장"}', '[{"id":"0c0ddd9f-14a3-48e7-a317-d7b7898dcd8d","korean":"선행하는","english":"prophecy"},{"id":"3d4aa24d-401d-47e6-af38-3849c07f0ebb","korean":"웅변적인","english":"eloquent"},{"id":"699a0ecb-48fe-4dd6-8786-820ba651e381","korean":"물 원소 피해 보너스+15%","english":"님프의 꿈의 2세트 효과는?"},{"id":"9319f202-7060-4e22-ac6d-4f7a615852fc","korean":"미리 결정된, 예정된","english":"predetermined"},{"id":"49cfb8d3-3d19-4ed3-88c7-7bff5052b070","korean":"외향적인 사람","english":"extrovert"}]', NULL, NULL, NULL) ON CONFLICT(exam_id) DO NOTHING;
INSERT INTO vocab_print_jobs (id, academy_id, student_id, word_ids_json, created_by, status, has_writing, started_at, submitted_at, created_at) VALUES ('vpj-sbw-96b873d1-0e3', 'acad-1', 'gst-sb-bfce39aa-959', '[]', 'supabase-import', 'voided', 1, '2026-03-20T07:02:41.538251+00:00', NULL, '2026-03-20T07:02:41.538251+00:00') ON CONFLICT(id) DO NOTHING;
INSERT INTO vocab_writing_responses (exam_id, problem_type, problem, target_words, student_answer, grade, graded_at) VALUES ('vpj-sbw-96b873d1-0e3', 'free_writing', '{"type":"free_writing","prompt":"Imagine you have the ability to foresee one specific future event. What event would you choose to see, and why? How might knowing this future impact your present actions or feelings, especially if the outcome seems inevitable or beyond your control?","conditions":["Use at least one sentence that expresses a personal preference or opinion.","Describe at least one potential consequence of knowing the future event."],"instruction":"주어진 질문에 대해 여러분의 생각이나 경험을 자유롭게 영어로 작성해 주세요. 여러분의 일상과 연결되는 친숙한 소재를 다룹니다.","expected_length":"4-6문장"}', '[{"id":"0c0ddd9f-14a3-48e7-a317-d7b7898dcd8d","korean":"선행하는","english":"prophecy"},{"id":"3d4aa24d-401d-47e6-af38-3849c07f0ebb","korean":"웅변적인","english":"eloquent"},{"id":"699a0ecb-48fe-4dd6-8786-820ba651e381","korean":"물 원소 피해 보너스+15%","english":"님프의 꿈의 2세트 효과는?"},{"id":"9319f202-7060-4e22-ac6d-4f7a615852fc","korean":"미리 결정된, 예정된","english":"predetermined"},{"id":"49cfb8d3-3d19-4ed3-88c7-7bff5052b070","korean":"외향적인 사람","english":"extrovert"}]', NULL, NULL, NULL) ON CONFLICT(exam_id) DO NOTHING;
INSERT INTO vocab_print_jobs (id, academy_id, student_id, word_ids_json, created_by, status, has_writing, started_at, submitted_at, created_at) VALUES ('vpj-sbw-93f1729f-b86', 'acad-1', 'gst-sb-bfce39aa-959', '[]', 'supabase-import', 'voided', 1, '2026-03-20T08:16:01.267791+00:00', NULL, '2026-03-20T08:16:01.267791+00:00') ON CONFLICT(id) DO NOTHING;
INSERT INTO vocab_writing_responses (exam_id, problem_type, problem, target_words, student_answer, grade, graded_at) VALUES ('vpj-sbw-93f1729f-b86', 'sentence_completion', '{"type":"sentence_completion","prompt":"어릴 적, 할머니는 저에게 신비로운 이야기를 자주 들려주셨습니다. 특히, 숲속의 요정들이 인간 세상에 나타나 예언을 하거나, 때로는 슬픔에 잠긴 영혼들을 위로한다는 이야기가 기억에 남습니다. 할머니는 종종 숲속의 님프들이 꿈속에서 아름다운 미래를 예견한다고 말씀하셨습니다.","conditions":["과거의 습관을 나타내는 ''used to'' 또는 ''would''를 사용하여 한 문장 이상 작성하세요.","화자의 내면적 성향이나 타인과의 관계를 묘사하는 내용을 포함하세요."],"instruction":"다음 지문의 내용을 바탕으로, 주어진 조건에 맞게 영어로 3-5문장의 글을 완성하세요.","expected_length":"3-5문장"}', '[{"id":"0c0ddd9f-14a3-48e7-a317-d7b7898dcd8d","korean":"선행하는","english":"prophecy"},{"id":"3d4aa24d-401d-47e6-af38-3849c07f0ebb","korean":"웅변적인","english":"eloquent"},{"id":"699a0ecb-48fe-4dd6-8786-820ba651e381","korean":"물 원소 피해 보너스+15%","english":"님프의 꿈의 2세트 효과는?"},{"id":"9319f202-7060-4e22-ac6d-4f7a615852fc","korean":"미리 결정된, 예정된","english":"predetermined"},{"id":"49cfb8d3-3d19-4ed3-88c7-7bff5052b070","korean":"외향적인 사람","english":"extrovert"}]', NULL, NULL, NULL) ON CONFLICT(exam_id) DO NOTHING;
