INSERT INTO vocab_writing_responses (exam_id, problem_type, problem, target_words, student_answer, grade, graded_at) VALUES ('vpj-sbw-c2de3963-cf3', 'word_arrangement', '{"type":"word_arrangement","prompt":"","word_list":"this/new/approach/can/furnish/us/with/further/knowledge/frankly","conditions":["주어는 ''This new approach''로 시작해야 합니다.","환경 보호를 위한 ''further'' 노력에 대한 내용을 포함해야 합니다.","솔직히(frankly) 말하면, 더 나은 결과를 위해 ''furnish''라는 단어를 사용해야 합니다."],"instruction":"주어진 8개의 단어를 올바른 순서로 배열하여 자연스러운 문장을 완성하세요. 단어의 형태 변형은 가능합니다.","expected_length":"2-3문장"}', '[{"id":"8782e0b1-b487-4e49-bf60-37b5a3e277f5","korean":"공급하다","english":"furnish"},{"id":"a7646f02-5e73-470f-955d-f0e74b7d1daf","korean":"한층더","english":"further"},{"id":"3e7307b0-e236-4aab-83c4-26411e4b6299","korean":"분수","english":"fraction"},{"id":"eb374ff2-9844-43b2-b149-7361535252b9","korean":"솔직히","english":"frankly"},{"id":"3c6eb985-fcdb-4bc7-b519-4491750d6dfe","korean":"기초의","english":"fundamental"}]', NULL, NULL, NULL) ON CONFLICT(exam_id) DO NOTHING;
