INSERT INTO vocab_writing_responses (exam_id, problem_type, problem, target_words, student_answer, grade, graded_at) VALUES ('vpj-sbw-5c4078e3-373', 'sentence_completion', '{"type":"sentence_completion","prompt":"최근 많은 사람들이 실내에서 보내는 시간이 늘어나면서, 집 안 환경을 개선하려는 노력이 활발해지고 있습니다. 특히, 편안하고 기능적인 공간을 만들기 위해 가구 배치나 소품 활용에 많은 관심을 보이고 있습니다. 이러한 변화는 단순히 미적인 만족감을 넘어, 우리의 심리적인 안정감과 생산성에도 긍정적인 영향을 줄 수 있다는 연구 결과가 나오고 있습니다.","conditions":["가정 환경 개선을 통해 ''한층 더'' 나은 삶의 질을 추구한다는 내용을 포함할 것.","이러한 노력이 ''솔직히'' 모든 사람에게 똑같은 정도의 효과를 주지는 않을 수 있다는 점을 언급할 것.","과거분사 구문을 사용하여 ''기초적인'' 가구의 중요성을 표현할 것."],"instruction":"주어진 상황을 바탕으로, 아래 조건에 맞게 영작하시오.","expected_length":"3-5문장"}', '[{"id":"8782e0b1-b487-4e49-bf60-37b5a3e277f5","korean":"공급하다","english":"furnish"},{"id":"a7646f02-5e73-470f-955d-f0e74b7d1daf","korean":"한층더","english":"further"},{"id":"3e7307b0-e236-4aab-83c4-26411e4b6299","korean":"분수","english":"fraction"},{"id":"eb374ff2-9844-43b2-b149-7361535252b9","korean":"솔직히","english":"frankly"},{"id":"3c6eb985-fcdb-4bc7-b519-4491750d6dfe","korean":"기초의","english":"fundamental"}]', NULL, NULL, NULL) ON CONFLICT(exam_id) DO NOTHING;
