INSERT INTO vocab_writing_responses (exam_id, problem_type, problem, target_words, student_answer, grade, graded_at) VALUES ('vpj-sbw-f5b05290-5ef', 'word_arrangement', '{"type":"word_arrangement","prompt":"demonstrate / maturity / simultaneous / submit / demonstration / the / a / and / to / public / their / will","conditions":["두 문장으로 완성해야 합니다.","첫 번째 문장에는 ''demonstrate''와 ''maturity''가 포함되어야 합니다.","두 번째 문장에는 ''simultaneous''와 ''submit''이 포함되어야 합니다."],"instruction":"주어진 단어들을 올바른 순서로 배열하여 두 문장으로 된 짧은 글을 완성하세요. 단어의 형태는 필요에 따라 변경할 수 있습니다.","expected_length":"2-3문장"}', '[{"id":"ebee4dd6-0e38-4cd2-b2fa-7f2059651ee8","korean":"보여주다, 입증하다","english":"demonstrate"},{"id":"aa02a46a-3183-4a82-b367-92fac3ef946a","korean":"성숙함","english":"maturity"},{"id":"e2800b39-c091-43bf-94bc-812e687371c5","korean":"동시에","english":"simultaneous"},{"id":"f91cb6c1-53b6-406d-a8cb-19a92fa6da3b","korean":"복종시키다","english":"submit"},{"id":"02b87a5c-3fbb-48d9-b431-a68a188d02ae","korean":"시위, 데모","english":"demonstration"}]', NULL, NULL, NULL) ON CONFLICT(exam_id) DO NOTHING;
INSERT INTO vocab_print_jobs (id, academy_id, student_id, word_ids_json, created_by, status, has_writing, started_at, submitted_at, created_at) VALUES ('vpj-sbw-b2699207-06e', 'acad-1', 'gst-sb-20969a71-24d', '[]', 'supabase-import', 'voided', 1, '2026-03-27T06:03:33.009373+00:00', NULL, '2026-03-27T06:03:33.009373+00:00') ON CONFLICT(id) DO NOTHING;
INSERT INTO vocab_writing_responses (exam_id, problem_type, problem, target_words, student_answer, grade, graded_at) VALUES ('vpj-sbw-b2699207-06e', 'summary_writing', '{"type":"summary_writing","prompt":"The concept of digital citizenship has become increasingly important in our interconnected world. It refers to the responsible and ethical use of technology, encompassing online safety, digital etiquette, and understanding one''s rights and responsibilities in the digital space.  Just as citizens in a physical community are expected to adhere to certain norms and laws, digital citizens must also cultivate a sense of responsibility. This involves not only protecting personal information but also engaging in respectful online interactions and being aware of the potential impact of one''s digital footprint.  Failing to develop strong digital citizenship skills can lead to various negative consequences, from cyberbullying and misinformation to privacy breaches and even identity theft. Therefore, fostering digital literacy and promoting responsible online behavior are crucial for individuals and society as a whole.","conditions":["Use at least one adverb that modifies an adjective or another adverb.","Your summary must mention both the definition of digital citizenship and its importance."],"instruction":"Read the following passage and summarize its main points in 2-3 sentences. Your summary should reflect an understanding of the author''s argument and the key concepts discussed. Ensure your summary adheres to the given grammatical and content conditions.","expected_length":"2-3 sentences"}', '[{"id":"ebee4dd6-0e38-4cd2-b2fa-7f2059651ee8","korean":"보여주다, 입증하다","english":"demonstrate"},{"id":"aa02a46a-3183-4a82-b367-92fac3ef946a","korean":"성숙함","english":"maturity"},{"id":"e2800b39-c091-43bf-94bc-812e687371c5","korean":"동시에","english":"simultaneous"},{"id":"f91cb6c1-53b6-406d-a8cb-19a92fa6da3b","korean":"복종시키다","english":"submit"},{"id":"02b87a5c-3fbb-48d9-b431-a68a188d02ae","korean":"시위, 데모","english":"demonstration"}]', NULL, NULL, NULL) ON CONFLICT(exam_id) DO NOTHING;
INSERT INTO vocab_print_jobs (id, academy_id, student_id, word_ids_json, created_by, status, has_writing, started_at, submitted_at, created_at) VALUES ('vpj-sbw-f330f829-dd5', 'acad-1', 'gst-sb-20969a71-24d', '[]', 'supabase-import', 'voided', 1, '2026-03-27T06:04:09.166176+00:00', NULL, '2026-03-27T06:04:09.166176+00:00') ON CONFLICT(id) DO NOTHING;
INSERT INTO vocab_writing_responses (exam_id, problem_type, problem, target_words, student_answer, grade, graded_at) VALUES ('vpj-sbw-f330f829-dd5', 'summary_writing', '{"type":"summary_writing","prompt":"In the realm of child development, the transition from adolescence to adulthood is often marked by a gradual increase in a person''s ability to make responsible decisions and understand complex situations. This development, known as maturity, is not a sudden event but a process that unfolds over time.  One significant aspect of this transition is the development of critical thinking skills, allowing individuals to analyze information, evaluate different perspectives, and form independent judgments.  Furthermore, as individuals mature, they often become more adept at managing their emotions and navigating social interactions with greater empathy and understanding.  These changes collectively demonstrate a growing capacity for self-governance and a deeper engagement with the world around them.","conditions":["Your summary must be written in the past tense.","Your summary should include the idea that maturity is a gradual process, not an instantaneous change."],"instruction":"Read the following passage and summarize its main points in 2-3 sentences. Your summary should accurately reflect the core message of the text and adhere to the given conditions.","expected_length":"2-3문장"}', '[{"id":"ebee4dd6-0e38-4cd2-b2fa-7f2059651ee8","korean":"보여주다, 입증하다","english":"demonstrate"},{"id":"aa02a46a-3183-4a82-b367-92fac3ef946a","korean":"성숙함","english":"maturity"},{"id":"e2800b39-c091-43bf-94bc-812e687371c5","korean":"동시에","english":"simultaneous"},{"id":"f91cb6c1-53b6-406d-a8cb-19a92fa6da3b","korean":"복종시키다","english":"submit"},{"id":"02b87a5c-3fbb-48d9-b431-a68a188d02ae","korean":"시위, 데모","english":"demonstration"}]', NULL, NULL, NULL) ON CONFLICT(exam_id) DO NOTHING;
